css:
/* Pickliste — scanbare Tabelle. Compact + groß genug für die typischen
   Handheld-Scanner. Barcodes als CSS-Streifen (Visual-Placeholder),
   echte Codes brauchen ein Barcode-Lib oder image-src. */

.sr-only {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
}

.pick-meta {
  margin-bottom: 6mm;
  padding-bottom: 4mm;
  border-bottom: 0.3mm solid #d1d5db;
  display: grid;
  grid-template-columns: 1fr 60mm;
  gap: 6mm;
  align-items: start;
}
.pick-meta__dl {
  display: grid;
  grid-template-columns: repeat(2, max-content 1fr);
  gap: 1mm 4mm;
  margin: 0;
  font-size: 9.5pt;
}
.pick-meta__dl > div {
  display: contents;
}
.pick-meta__dl dt {
  font-weight: 700;
  color: #4b5563;
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  align-self: center;
}
.pick-meta__dl dd { margin: 0; }
.pick-meta__addr dd { line-height: 1.35; }

.pick-meta__tour {
  text-align: center;
  padding: 2mm;
  border: 0.3mm solid #d1d5db;
  border-radius: 1mm;
}
.pick-meta__tour-label {
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.4px;
  text-transform: uppercase;
  color: #4b5563;
  margin-bottom: 2mm;
}

/* Barcode — CSS-Streifen-Placeholder. Echte Bars werden später als
   <img>-Element vom Backend ersetzt (Code-128 / EAN-13). */
.barcode {
  height: 12mm;
  background:
    repeating-linear-gradient(
      to right,
      #111827 0 0.5mm,
      transparent 0.5mm 0.8mm,
      #111827 0.8mm 1.2mm,
      transparent 1.2mm 1.8mm,
      #111827 1.8mm 2.3mm,
      transparent 2.3mm 2.9mm,
      #111827 2.9mm 3.2mm,
      transparent 3.2mm 4mm
    );
  margin: 0 auto;
  max-width: 100%;
}
.barcode--row {
  height: 7mm;
  width: 36mm;
  margin: 0;
}
.barcode__caption {
  font-family: monospace;
  font-size: 8.5pt;
  text-align: center;
  margin-top: 1mm;
  letter-spacing: 0.5pt;
}
.barcode__caption--row {
  font-size: 7.5pt;
  text-align: left;
  letter-spacing: 0.3pt;
}

.pick-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
  margin-top: 2mm;
}
.pick-table thead th {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  text-align: left;
  background: #f3f4f6;
  border-bottom: 0.4mm solid #6b7280;
  padding: 2mm 3mm;
  color: #374151;
}
.pick-table tbody td {
  padding: 2.5mm 3mm;
  border-bottom: 0.2mm solid #e5e7eb;
  vertical-align: middle;
}
.pick-table__col-loc {
  width: 22mm;
  font-weight: 700;
  font-family: monospace;
  font-size: 10pt;
  letter-spacing: 0.5pt;
}
.pick-table__col-bar  { width: 40mm; }
.pick-table__col-qty  {
  width: 18mm;
  text-align: right;
  font-variant-numeric: tabular-nums;
  font-size: 12pt;
}
.pick-table__col-unit { width: 14mm; color: #6b7280; }
.pick-table__col-check { width: 12mm; text-align: center; }
.pick-table__ean {
  font-size: 8pt;
  color: #6b7280;
  margin-top: 0.5mm;
}

.pick-checkbox {
  display: inline-block;
  width: 6mm;
  height: 6mm;
  border: 0.4mm solid #111827;
  border-radius: 0.5mm;
}

.pick-signatures {
  margin-top: 12mm;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12mm;
}
.pick-sig__line {
  border-bottom: 0.3mm solid #111827;
  height: 16mm;
}
.pick-sig__label {
  font-size: 9pt;
  color: #6b7280;
  margin-top: 1mm;
}
